tcmpOp = \\\"<\\\"\\n402\\t+\\t\\t} else {\\n403\\t+\\t\\t\\tcmpOp = \\\">\\\"\\n404\\t+\\t\\t}\\n405\\t+\\t}\\n406\\t+\\tif unit != \\\"\\\" {\\n407\\t+\\t\\treturn fmt.Sprintf(\\\"%s: observed %g %s %s ratchet %g %s\\\", state, observed, unit, cmpOp, threshold, unit)\\n408\\t+\\t}\\n409\\t+\\treturn fmt.Sprintf(\\\"%s: observed %g %s ratchet %g\\\", state, observed, cmpOp, threshold)\\n410\\t+}\\n411\\t+\\n412\\t+// parseGateValue extracts a numeric observation from gate output. Accepts\\n413\\t+// either a JSON object with a \\\"value\\\" (and optional \\\"unit\\\") field, or a\\n414\\t+// trailing number with an optional unit suffix. Returns the value, the parsed\\n415\\t+// unit (may be \\\"\\\"), and whether parsing succeeded.\\n416\\t+func parseGateValue(text string) (float64, string, bool) {\\n417\\t+\\ttext = strings.TrimSpace(text)\\n418\\t+\\tif text == \\\"\\\" {\\n419\\t+\\t\\treturn 0, \\\"\\\", false\\n420\\t+\\t}\\n421\\t+\\tif v, u, ok := parseGateJSON(text); ok {\\n422\\t+\\t\\treturn v, u, true\\n423\\t+\\t}\\n424\\t+\\treturn parseGateText(text)\\n425\\t+}\\n426\\t+\\n427\\t+var gateMeasurementPattern = regexp.MustCompile(`(-?\\\\d+(?:\\\\.\\\\d+)?)(?:\\\\s*)([a-zA-Z%/]+)?`)\\n428\\t+\\n429\\t+func parseGateJSON(text string) (float64, string, bool) {\\n430\\t+\\tvar obj map[string]any\\n431\\t+\\tif err := json.Unmarshal([]byte(text), &obj); err != nil {\\n432\\t+\\t\\treturn 0, \\\"\\\", false\\n433\\t+\\t}\\n434\\t+\\traw, ok := obj[\\\"value\\\"]\\n435\\t+\\tif !ok {\\n436\\t+\\t\\treturn 0, \\\"\\\", false\\n437\\t+\\t}\\n438\\t+\\tunit, _ := obj[\\\"unit\\\"].(string)\\n439\\t+\\tswitch v := raw.(type) {\\n440\\t+\\tcase float64:\\n441\\t+\\t\\treturn v, unit, true\\n442\\t+\\tcase string:\\n443\\t+\\t\\tif parsed, err := strconv.ParseFloat(v, 64); err == nil {\\n444\\t+\\t\\t\\treturn parsed, unit, true\\n445\\t+\\t\\t}\\n446\\t+\\t}\\n447\\t+\\treturn 0, \\\"\\\", false\\n448\\t+}\\n449\\t+\\n450\\t+func parseGateText(text string) (float64