.WriteString(\\\"      unit: \\\" + unit + \\\"\\\\n\\\")\\n544\\t+\\t\\t}\\n545\\t+\\t}\\n546\\t+\\tsb.WriteString(\\\"---\\\\n# \\\" + id + \\\"\\\\n\\\")\\n547\\t+\\tif err := os.WriteFile(path, []byte(sb.String()), 0o644); err != nil {\\n548\\t+\\t\\tt.Fatal(err)\\n549\\t+\\t}\\n550\\t+}\\n551\\t+\\n552\\t+// TestEvaluateRequiredGates_RatchetPass verifies a gate whose observed value\\n553\\t+// satisfies the ratchet returns status=pass with a machine-readable decision.\\n554\\t+func TestEvaluateRequiredGates_RatchetPass(t *testing.T) {\\n555\\t+\\tdir := t.TempDir()\\n556\\t+\\twriteArtifactDoc(t, dir, \\\"FEAT-RATCHET-PASS\\\")\\n557\\t+\\twriteRatchetGateDoc(t, dir, \\\"exec.FEAT-RATCHET-PASS.latency\\\", \\\"FEAT-RATCHET-PASS\\\",\\n558\\t+\\t\\t[]string{\\\"sh\\\", \\\"-c\\\", \\\"echo 120\\\"}, \\\"lower-is-better\\\", 250, \\\"ms\\\", \\\"MET-LATENCY\\\")\\n559\\t+\\n560\\t+\\tresults, anyFailed, anyRatchetFailed, err := evaluateRequiredGates(dir, []string{\\\"FEAT-RATCHET-PASS\\\"})\\n561\\t+\\tif err != nil {\\n562\\t+\\t\\tt.Fatalf(\\\"unexpected error: %v\\\", err)\\n563\\t+\\t}\\n564\\t+\\tif anyFailed {\\n565\\t+\\t\\tt.Error(\\\"expected anyFailed=false for passing ratchet\\\")\\n566\\t+\\t}\\n567\\t+\\tif anyRatchetFailed {\\n568\\t+\\t\\tt.Error(\\\"expected anyRatchetFailed=false when observed <= ratchet\\\")\\n569\\t+\\t}\\n570\\t+\\tif len(results) != 1 {\\n571\\t+\\t\\tt.Fatalf(\\\"expected 1 result, got %d\\\", len(results))\\n572\\t+\\t}\\n573\\t+\\tgr := results[0]\\n574\\t+\\tif gr.Status != \\\"pass\\\" {\\n575\\t+\\t\\tt.Errorf(\\\"expected status=pass, got %q\\\", gr.Status)\\n576\\t+\\t}\\n577\\t+\\tif gr.Ratchet == nil {\\n578\\t+\\t\\tt.Fatal(\\\"expected ratchet evidence on passing gate\\\")\\n579\\t+\\t}\\n580\\t+\\tif gr.Ratchet.Decision != \\\"pass\\\" {\\n581\\t+\\t\\tt.Errorf(\\\"expected ratchet decision=pass, got %q\\\", gr.Ratchet.Decision)\\n582\\t+\\t}\\n583\\t+\\tif gr.Ratchet.Threshold != 250 {\\n584\\t+\\t\\tt.Errorf(\\