692	func (s *Store) SetExecutionCooldown(id string, until time.Time, status, detail string) error {
693		return s.Update(id, func(b *Bead) {
694			if b.Extra == nil {
695				b.Extra = make(map[string]any)
696			}
697			b.Extra["execute-loop-retry-after"] = until.UTC().Format(time.RFC3339)
698			if status != "" {
699				b.Extra["execute-loop-last-status"] = status
700			}
701			if detail != "" {
702				b.Extra["execute-loop-last-detail"] = detail
703			}
704		})
705	}
706	
707	// IncrNoChangesCount increments the execute-loop no-changes counter for a bead
708	// and returns the new count. Used by the execute-bead worker to detect when a
709	// bead should be auto-closed after repeated no-change attempts.
710	func (s *Store) IncrNoChangesCount(id string) (int, error) {
711		var newCount int
712		err := s.Update(id, func(b *Bead) {
713			if b.Extra == nil {
714				b.Extra = make(map[string]any)
715			}
716			var count int
717			if v, ok := b.Extra["execute-loop-no-changes-count"]; ok {
718				switch n := v.(type) {
719				case int:
720					count = n
721				case float64:
722					count = int(n)
723				case int64:
724					count = int(n)
725				}
726			}
727			count++
728			b.Extra["execute-loop-no-changes-count"] = count
729			newCount = count
730		})
731		return newCount, err
732	}
733	
734	// MaxFieldBytes is the per-field hard cap on bead event bodies and adjacent
735	// writer paths. 65,535 bytes matches upstream bd's Dolt TEXT column size so
736	// DDx-authored beads always round-trip through `bd import`. Empirically
737	// validated against bd 1.0.2 on 2026-04-20: 65,535 accepts, 65,536 rejects.
738	const MaxFieldBytes = 65535
739	
740	// capFieldBytes enforces MaxFieldBytes on a single field value. Callers that
741	// need to preserve the full payload should persist it to a sidecar artifact
742	// and store a path reference in the field; this function is the defense-in-
743	// depth cap for code paths that don't. Returns the input unchanged when it
744	// fits; otherwise returns head+tail truncation with a byte-count marker.
745	func capFieldBytes(s string) string {
746		if len(s) <= MaxFieldBytes {
747			return s
748		}
749		// Reserve a marker that always fits; keep head heavy (2/3) so
750		// human-readable context is preserved for the common short-rationale case.
751		marker := fmt.Sprintf("\n…[truncated, %d bytes]\n", len(s))
752		budget := MaxFieldBytes - len(marker)
753		if budget <= 0 {
754			return s[:MaxFieldBytes]
755		}
756		head := (budget * 2) / 3
757		tail := budget - head
758		return s[:head] + marker + s[len(s)-tail:]
759	}
760	
761	func (s *Store) AppendEvent(id string, event BeadEvent) error {
762		if event.CreatedAt.IsZero() {
763			event.CreatedAt = time.Now().UTC()
764		}
765		// Defense in depth: cap every event body regardless of caller. The
766		// reviewer write path separately persists the full stream to an artifact
767		// and emits a <=512-byte body; this cap catches anything else.
768		event.Body = capFieldBytes(event.Body)
769		event.Summary = capFieldBytes(event.Summary)
770		return s.Update(id, func(b *Bead) {
771			if b.Extra == nil {
772				b.Extra = make(map[string]any)
773			}
774			var events []BeadEvent
775			if raw, ok := b.Extra["events"]; ok {
776				events = decodeBeadEvents(raw)
777			}
778			events = append(events, event)
779			encoded := make([]map[string]any, 0, len(events))
780			for _, e := range events {
781				encoded = append(encoded, map[string]any{
782					"kind":       e.Kind,
783					"summary":    e.Summary,
784					"body":       e.Body,
785					"actor":      e.Actor,
786					"created_at": e.CreatedAt,
787					"source":     e.Source,
788				})
789			}
790			b.Extra["events"] = encoded
791		})
792	}
