851	func beadEventFromMap(m map[string]any) BeadEvent {
852		e := BeadEvent{}
853		if v, ok := m["kind"].(string); ok {
854			e.Kind = v
855		}
856		if v, ok := m["summary"].(string); ok {
857			e.Summary = v
858		}
859		if v, ok := m["body"].(string); ok {
860			e.Body = v
861		}
862		if v, ok := m["actor"].(string); ok {
863			e.Actor = v
864		}
865		if v, ok := m["source"].(string); ok {
866			e.Source = v
867		}
868		if v, ok := m["created_at"].(string); ok {
869			if parsed, err := time.Parse(time.RFC3339, v); err == nil {
870				e.CreatedAt = parsed
871			}
872		}
873		return e
874	}
