991	// Reopen sets a bead's status back to open, clears claim fields, optionally
992	// appends notes, and records an immutable reopen event — all in one atomic
993	// lock acquisition.
994	func (s *Store) Reopen(id string, reason string, appendNotes string) error {
995		now := time.Now().UTC()
996		return s.WithLock(func() error {
997			beads, _, err := s.readAllLatestRaw()
998			if err != nil {
999				return err
1000			}
1001			found := false
1002			for i := range beads {
1003				if beads[i].ID != id {
1004					continue
1005				}
1006				b := &beads[i]
1007				b.Status = StatusOpen
1008				b.Owner = ""
1009				b.UpdatedAt = now
1010				if b.Extra == nil {
1011					b.Extra = make(map[string]any)
1012				}
1013				// Clear claim fields
1014				delete(b.Extra, "claimed-at")
1015				delete(b.Extra, "claimed-pid")
1016				delete(b.Extra, "claimed-machine")
1017				delete(b.Extra, "claimed-session")
1018				delete(b.Extra, "claimed-worktree")
1019				delete(b.Extra, "execute-loop-heartbeat-at")
1020				// Append notes
1021				if appendNotes != "" {
1022					if b.Notes != "" {
1023						b.Notes = b.Notes + "\n\n" + appendNotes
1024					} else {
1025						b.Notes = appendNotes
1026					}
1027				}
1028				// Record reopen event
1029				var events []BeadEvent
1030				if raw, ok := b.Extra["events"]; ok {
1031					events = decodeBeadEvents(raw)
1032				}
1033				evt := BeadEvent{
1034					Kind:      "reopen",
1035					CreatedAt: now,
1036				}
1037				if reason != "" {
1038					evt.Summary = reason
1039				}
1040				events = append(events, evt)
1041				encoded := make([]map[string]any, 0, len(events))
1042				for _, e := range events {
1043					encoded = append(encoded, map[string]any{
1044						"kind":       e.Kind,
1045						"summary":    e.Summary,
1046						"body":       e.Body,
1047						"actor":      e.Actor,
1048						"created_at": e.CreatedAt,
1049						"source":     e.Source,
1050					})
1051				}
1052				b.Extra["events"] = encoded
1053				if err := s.validateBead(b); err != nil {
1054					return err
1055				}
1056				if err := s.runHook("validate-bead-update", b); err != nil {
1057					return err
1058				}
1059				found = true
1060				break
1061			}
1062			if !found {
1063				return fmt.Errorf("bead: not found: %s", id)
1064			}
1065			return s.WriteAll(beads)
1066		})
1067	}
