1078	// List returns beads matching optional filters.
1079	// where is an optional map of key=value predicates that match against
1080	// known struct fields and Extra (unknown/workflow-specific) fields.
1081	func (s *Store) List(status, label string, where map[string]string) ([]Bead, error) {
1082		beads, err := s.ReadAll()
1083		if err != nil {
1084			return nil, err
1085		}
1086		var result []Bead
1087		for _, b := range beads {
1088			if status != "" && b.Status != status {
1089				continue
1090			}
1091			if label != "" && !containsString(b.Labels, label) {
1092				continue
1093			}
1094			if !matchesWhere(b, where) {
1095				continue
1096			}
1097			result = append(result, b)
1098		}
1099		return result, nil
1100	}
1101	
1102	// matchesWhere returns true if the bead satisfies all key=value predicates.
1103	// It checks known struct fields first, then falls back to Extra.
1104	func matchesWhere(b Bead, where map[string]string) bool {
1105		for k, v := range where {
1106			var actual string
1107			switch k {
1108			case "id":
1109				actual = b.ID
1110			case "title":
1111				actual = b.Title
1112			case "status":
1113				actual = b.Status
1114			case "issue_type":
1115				actual = b.IssueType
1116			case "owner":
1117				actual = b.Owner
1118			case "assignee":
1119				actual = b.Owner
1120			case "parent":
1121				actual = b.Parent
1122			case "description":
1123				actual = b.Description
1124			case "acceptance":
1125				actual = b.Acceptance
1126			case "notes":
1127				actual = b.Notes
1128			default:
1129				// Fall back to Extra map for unknown/workflow-specific fields
1130				if b.Extra != nil {
1131					if ev, ok := b.Extra[k]; ok {
1132						actual = fmt.Sprintf("%v", ev)
1133					}
1134				}
1135			}
1136			if actual != v {
1137				return false
1138			}
1139		}
1140		return true
1141	}
1142	
1143	// Ready returns open beads whose dependencies are all closed, sorted by
1144	// priority (0 = highest first).
1145	func (s *Store) Ready() ([]Bead, error) {
1146		return s.readyFiltered(false)
1147	}
1148	
1149	// ReadyExecution returns ready beads that are also execution-eligible and
1150	// not superseded. This is the filter HELIX uses for its build loop.
1151	func (s *Store) ReadyExecution() ([]Bead, error) {
1152		return s.readyFiltered(true)
1153	}
1154	
1155	// ReadyExecutionBreakdown classifies dependency-ready beads by the reason
1156	// they are NOT execution-eligible: epic containers, retry cooldown,
1157	// execution-eligible=false, or superseded. It's the diagnostic the work loop
1158	// emits when the execution queue is empty but `ddx bead ready` is not.
1159	type ReadyExecutionBreakdown struct {
1160		SkippedEpics       []string
1161		SkippedOnCooldown  []string
1162		SkippedNotEligible []string
1163		SkippedSuperseded  []string
1164		NextRetryAfter     string
1165	}
1166	
1167	func (s *Store) ReadyExecutionBreakdown() (ReadyExecutionBreakdown, error) {
1168		out := ReadyExecutionBreakdown{}
1169		ready, err := s.Ready()
1170		if err != nil {
1171			return out, err
1172		}
1173		now := time.Now().UTC()
1174		var soonestRetry time.Time
1175		for _, b := range ready {
1176			if retryAfterRaw, ok := b.Extra["execute-loop-retry-after"]; ok {
1177				if retryAfterStr, isStr := retryAfterRaw.(string); isStr && retryAfterStr != "" {
1178					if retryAfter, err := time.Parse(time.RFC3339, retryAfterStr); err == nil && retryAfter.After(now) {
1179						out.SkippedOnCooldown = append(out.SkippedOnCooldown, b.ID)
1180						if soonestRetry.IsZero() || retryAfter.Before(soonestRetry) {
1181							soonestRetry = retryAfter
1182						}
1183						continue
1184					}
1185				}
1186			}
1187			if eligible, ok := b.Extra["execution-eligible"]; ok {
1188				if val, isBool := eligible.(bool); isBool && !val {
1189					out.SkippedNotEligible = append(out.SkippedNotEligible, b.ID)
1190					continue
1191				}
1192			}
1193			if sup, ok := b.Extra["superseded-by"]; ok {
1194				if s, isStr := sup.(string); isStr && s != "" {
1195					out.SkippedSuperseded = append(out.SkippedSuperseded, b.ID)
1196					continue
1197				}
1198			}
1199		}
1200		if !soonestRetry.IsZero() {
1201			out.NextRetryAfter = soonestRetry.Format(time.RFC3339)
1202		}
1203		return out, nil
1204	}
1205	
1206	func (s *Store) readyFiltered(executionOnly bool) ([]Bead, error) {
1207		beads, err := s.ReadAll()
1208		if err != nil {
1209			return nil, err
1210		}
1211		statusMap := make(map[string]string)
1212		for _, b := range beads {
1213			statusMap[b.ID] = b.Status
1214		}
1215	
1216		var ready []Bead
1217		for _, b := range beads {
1218			if b.Status != StatusOpen {
1219				// Surface stalled in_progress beads so a fresh worker can
1220				// reclaim them atomically in Claim().
1221				if executionOnly && b.Status == StatusInProgress && heartbeatIsStale(b.Extra) {
1222					// fall through to dependency check below
1223				} else {
1224					continue
1225				}
1226			}
1227			allSatisfied := true
1228			for _, depID := range b.DepIDs() {
1229				if statusMap[depID] != StatusClosed {
1230					allSatisfied = false
1231					break
1232				}
1233			}
1234			if !allSatisfied {
1235				continue
1236			}
1237			if executionOnly {
1238				// Filter by execution-eligible (default true if absent)
1239				eligible, ok := b.Extra["execution-eligible"]
1240				if ok {
1241					if val, isBool := eligible.(bool); isBool && !val {
1242						continue
1243					}
1244				}
1245				// Filter out superseded beads
1246				if sup, ok := b.Extra["superseded-by"]; ok {
1247					if s, isStr := sup.(string); isStr && s != "" {
1248						continue
1249					}
1250				}
1251				if retryAfterRaw, ok := b.Extra["execute-loop-retry-after"]; ok {
1252					if retryAfterStr, isStr := retryAfterRaw.(string); isStr && retryAfterStr != "" {
1253						if retryAfter, err := time.Parse(time.RFC3339, retryAfterStr); err == nil && retryAfter.After(time.Now().UTC()) {
1254							continue
1255						}
1256					}
1257				}
1258			}
1259			ready = append(ready, b)
1260		}
1261	
1262		sortBeadsForQueue(ready)
1263	
1264		return ready, nil
1265	}
1266	
1267	// Blocked returns open beads with at least one unclosed dependency.
1268	func (s *Store) Blocked() ([]Bead, error) {
1269		beads, err := s.ReadAll()
1270		if err != nil {
1271			return nil, err
1272		}
1273		statusMap := make(map[string]string)
1274		for _, b := range beads {
1275			statusMap[b.ID] = b.Status
1276		}
1277	
1278		var blocked []Bead
1279		for _, b := range beads {
1280			if b.Status != StatusOpen {
1281				continue
1282			}
1283			for _, depID := range b.DepIDs() {
1284				if statusMap[depID] != StatusClosed {
1285					blocked = append(blocked, b)
1286					break
1287				}
1288			}
1289		}
1290		sortBeadsForQueue(blocked)
1291		return blocked, nil
1292	}
1293	
1294	// BlockedAll returns open beads that are currently not runnable, classified
1295	// by blocker kind. Dependency-blocked beads are emitted first (any unclosed
1296	// dep in their DAG); retry-parked beads whose execute-loop-retry-after is in
1297	// the future are emitted with blocker kind BlockerKindRetryCooldown. A bead
1298	// that is both dep-blocked and cooldown-parked is reported as dependency-
1299	// blocked, because deps are the stronger blocker.
1300	func (s *Store) BlockedAll() ([]BlockedBead, error) {
1301		beads, err := s.ReadAll()
1302		if err != nil {
1303			return nil, err
1304		}
1305		statusMap := make(map[string]string)
1306		for _, b := range beads {
1307			statusMap[b.ID] = b.Status
1308		}
1309	
1310		now := time.Now().UTC()
1311		var entries []BlockedBead
1312		for _, b := range beads {
1313			if b.Status != StatusOpen {
1314				continue
1315			}
1316	
1317			var unclosed []string
1318			for _, depID := range b.DepIDs() {
1319				if statusMap[depID] != StatusClosed {
1320					unclosed = append(unclosed, depID)
1321				}
1322			}
1323			if len(unclosed) > 0 {
1324				entries = append(entries, BlockedBead{
1325					Bead: b,
1326					Blocker: Blocker{
1327						Kind:           BlockerKindDependency,
1328						UnclosedDepIDs: unclosed,
1329					},
1330				})
1331				continue
1332			}
1333	
1334			retryAfterRaw, ok := b.Extra["execute-loop-retry-after"]
1335			if !ok {
1336				continue
1337			}
1338			retryAfterStr, isStr := retryAfterRaw.(string)
1339			if !isStr || retryAfterStr == "" {
1340				continue
1341			}
1342			retryAfter, err := time.Parse(time.RFC3339, retryAfterStr)
1343			if err != nil || !retryAfter.After(now) {
1344				continue
1345			}
1346			blocker := Blocker{
1347				Kind:           BlockerKindRetryCooldown,
1348				NextEligibleAt: retryAfter.UTC().Format(time.RFC3339),
1349			}
1350			if v, ok := b.Extra["execute-loop-last-status"]; ok {
1351				if s, ok := v.(string); ok {
1352					blocker.LastStatus = s
1353				}
1354			}
1355			if v, ok := b.Extra["execute-loop-last-detail"]; ok {
1356				if s, ok := v.(string); ok {
1357					blocker.LastDetail = s
1358				}
1359			}
1360			entries = append(entries, BlockedBead{
1361				Bead:    b,
1362				Blocker: blocker,
1363			})
1364		}
1365	
1366		sort.SliceStable(entries, func(i, j int) bool {
1367			if entries[i].Priority != entries[j].Priority {
1368				return entries[i].Priority < entries[j].Priority
1369			}
1370			if !entries[i].CreatedAt.Equal(entries[j].CreatedAt) {
1371				return entries[i].CreatedAt.Before(entries[j].CreatedAt)
1372			}
1373			return entries[i].ID < entries[j].ID
1374		})
1375		return entries, nil
1376	}
1377	
1378	func sortBeadsForQueue(beads []Bead) {
1379		sort.SliceStable(beads, func(i, j int) bool {
1380			if beads[i].Priority != beads[j].Priority {
1381				return beads[i].Priority < beads[j].Priority
1382			}
1383			if !beads[i].CreatedAt.Equal(beads[j].CreatedAt) {
1384				return beads[i].CreatedAt.Before(beads[j].CreatedAt)
1385			}
1386			return beads[i].ID < beads[j].ID
1387		})
1388	}
1389	
1390	// Status returns aggregate counts.
1391	func (s *Store) Status() (*StatusCounts, error) {
1392		beads, err := s.ReadAll()
1393		if err != nil {
1394			return nil, err
1395		}
1396		ready, err := s.Ready()
1397		if err != nil {
1398			return nil, err
1399		}
1400		blocked, err := s.Blocked()
1401		if err != nil {
1402			return nil, err
1403		}
1404	
1405		counts := &StatusCounts{Total: len(beads), Ready: len(ready), Blocked: len(blocked)}
1406		for _, b := range beads {
1407			switch b.Status {
1408			case StatusOpen:
1409				counts.Open++
1410			case StatusClosed:
1411				counts.Closed++
1412			}
1413		}
1414		return counts, nil
1415	}
