1470	// DepTree returns a text representation of the dependency tree.
1471	func (s *Store) DepTree(rootID string) (string, error) {
1472		beads, err := s.ReadAll()
1473		if err != nil {
1474			return "", err
1475		}
1476		byID := make(map[string]*Bead)
1477		for i := range beads {
1478			byID[beads[i].ID] = &beads[i]
1479		}
1480	
1481		if rootID != "" {
1482			target, ok := byID[rootID]
1483			if !ok {
1484				return "", fmt.Errorf("bead: not found: %s", rootID)
1485			}
1486			var sb strings.Builder
1487			// Walk up: show the dependency chain (what this node depends on)
1488			depChain := s.depChainUp(byID, rootID)
1489			if len(depChain) > 0 {
1490				// Print deps as the tree root(s), with the target as their child
1491				for _, depID := range depChain {
1492					if dep, ok := byID[depID]; ok {
1493						fmt.Fprintf(&sb, "%s [%s] %s\n", dep.ID, dep.Status, dep.Title)
1494					}
1495				}
1496			}
1497			// Print the target node
1498			fmt.Fprintf(&sb, "%s [%s] %s\n", target.ID, target.Status, target.Title)
1499			// Print dependents (what depends on this node)
1500			var children []string
1501			for _, other := range sortedKeys(byID) {
1502				if byID[other].HasDep(rootID) {
1503					children = append(children, other)
1504				}
1505			}
1506			for _, child := range children {
1507				s.printTree(&sb, byID, child, "  ", true)
1508			}
1509			return sb.String(), nil
1510		}
1511	
1512		// Find roots (beads that have no dependencies themselves)
1513		var roots []string
1514		for _, b := range beads {
1515			if len(b.Dependencies) == 0 {
1516				roots = append(roots, b.ID)
1517			}
1518		}
1519		sort.Strings(roots)
1520	
1521		var sb strings.Builder
1522		for i, root := range roots {
1523			s.printTree(&sb, byID, root, "", i == len(roots)-1)
1524		}
1525		return sb.String(), nil
1526	}
