1595	// detectPrefix derives the bead ID prefix from the repository/directory name,
1596	// following the bd convention (e.g., repo "my-project" → prefix "my-project").
1597	// workingDir is the project root to use for git commands; when empty the
1598	// process working directory is used (legacy behaviour, prone to worktree
1599	// path contamination). Falls back to DefaultPrefix if detection fails.
1600	func detectPrefix(workingDir string) string {
1601		// Try git repo root name first, running from the known project root so
1602		// that linked worktrees (e.g. execute-bead isolated worktrees) do not
1603		// contaminate the prefix with their ephemeral directory names.
1604		cmd := gitpkg.Command(context.Background(), workingDir, "rev-parse", "--show-toplevel")
1605		if out, err := cmd.Output(); err == nil {
1606			root := strings.TrimSpace(string(out))
1607			if root != "" {
1608				return filepath.Base(root)
1609			}
1610		}
1611		// Fall back to the provided working dir, then cwd.
1612		if workingDir != "" {
1613			return filepath.Base(workingDir)
1614		}
1615		if wd, err := os.Getwd(); err == nil {
1616			return filepath.Base(wd)
1617		}
1618		return DefaultPrefix
1619	}
